<template>
  <div class="page-information">
    <div class="tools">
      是否开启通知：
      <el-switch
        v-loading="loadingStatus"
        :value="messageStatus"
        :active-value="1"
        :inactive-value="0"
        @click.native="handleChangeStatus"
      />
    </div>
    <SpFilterForm :model="params" @onSearch="onSearch" @onReset="onReset">
      <SpFilterFormItem prop="msg_type" label="訊息類型:">
        <el-select v-model="params.msg_type" placeholder="請選擇訊息類型" clearable @change="onSearch">
          <el-option
            v-for="(item, index) in typeList"
            :key="index"
            :label="item.label"
            :value="item.value"
          />
        </el-select>
      </SpFilterFormItem>
      <SpFilterFormItem prop="msg_name" label="訊息名稱:">
        <el-input v-model="params.msg_name" clearable placeholder="請輸入訊息名稱" @keydown.enter.native="onSearch" />
      </SpFilterFormItem>
    </SpFilterForm>

    <div class="list">
      <el-table v-loading="loading" border :data="tableList" element-loading-text="數據加載中">
        <el-table-column prop="id" label="訊息ID" />
        <el-table-column prop="msg_type" label="訊息類型">
          <template slot-scope="scope">
            {{ getMessageTypeName(scope.row.msg_type) }}
          </template>
        </el-table-column>
        <el-table-column prop="msg_name" label="訊息名稱" />
        <el-table-column prop="content" label="場景內容資料結構data" />
        <el-table-column prop="create_time_txt" label="推播時間" />
        <el-table-column prop="is_read_txt" label="閱讀狀態" />
      </el-table>
    </div>

    <div class="content-padded content-center">
      <el-pagination
        background
        layout="total, sizes, prev, pager, next, jumper"
        :current-page.sync="page.pageIndex"
        :page-sizes="[10, 20, 50]"
        :total="page.total"
        :page-size="page.pageSize"
        @current-change="onCurrentChange"
        @size-change="onSizeChange"
      />
    </div>
  </div>
</template>

<script>
import mixin, { pageMixin } from '@/mixins'
export default {
  name: 'SettingInformation',
  components: {},
  mixins: [mixin, pageMixin],
  props: {},
  data() {
    return {
      initialParams: {
        msg_type: null,
        msg_name: null
      },
      params: {
        msg_type: null,
        msg_name: null
      },
      typeList: [],
      messageStatus: 0,
      loadingStatus: 0,
      loading: false,
      tableList: []
    };
  },
  computed: {},
  watch: {},
  created() {
    this.getPushMessageType()
    this.getPushMessageStatus()
    this.fetchList()
  },
  methods: {
    onSearch() {
      this.page.pageIndex = 1
      this.$nextTick(() => {
        this.fetchList()
      })
    },
    onReset() {
      this.params = { ...this.initialParams }
      this.onSearch()
    },
    getPushMessageStatus() {
      this.$api.company.getPushMessageStatus().then(data => {
        this.messageStatus = +data.status
      })
    },
    handleChangeStatus() {
      // const status = this.messageStatus ? 0 : 1
      const status = 1
      this.loadingStatus = true
      this.$api.company.setPushMessageStatus({
        status
      }).then(() => {
        this.messageStatus = status
      }).finally(() => {
        this.loadingStatus = false
      })
    },
    getPushMessageType() {
      this.$api.company.getPushMessageType().then(data => {
        for (const key in data) {
          this.typeList.push({
            label: data[key],
            value: key
          })
        }
      })
    },
    getMessageTypeName(value) {
      const find = this.typeList.find(item => item.value === value)
      if (find) {
        return find.label
      } else {
        return value
      }
    },
    async fetchList() {
      this.loading = true
      const { pageIndex: page, pageSize } = this.page
      let params = {
        page,
        pageSize,
        ...this.params
      }
      const { list, total_count } = await this.$api.company.getPushMessageList(params)
      this.tableList = (list || []).map(item => {
        return {
          ...item,
          loading: false
        }
      })
      this.page.total = total_count
      this.loading = false
    }
  }
};
</script>

<style lang="scss" scoped>
  .page-information{
    .tools{ padding-bottom: 10px;}
    .list{ padding-top: 10px;}
  }
</style>
